#include <stdio.h>
#include <math.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld", &N);
        long long d = N; // default: N itself (prime case)
        long long limit = sqrt((double)N);
        for(long long i=2;i<=limit;i++){
            if(N % i == 0){ d = i; break; }
        }
        long long X = N + N / d;
        printf("%lld\n", X);
    }
    return 0;
}

