#!/usr/bin/env python3
import sys,math

def smallest_divisor(n):
    i=2
    while i*i<=n:
        if n%i==0:
            return i
        i+=1
    return n

def main():
    data=sys.stdin.read().strip().split()
    if not data: return
    it=iter(data)
    T=int(next(it))
    out=[]
    for _ in range(T):
        N=int(next(it))
        d=smallest_divisor(N)
        X=N+N//d
        out.append(str(X))
    sys.stdout.write('\n'.join(out))

if __name__=="__main__":
    main()

